3975	\begin{lemma}[Sections of a restricted module are sections over the image open]
3976	  \label{lem:restrict_obj_mathlib}
3977	  \lean{AlgebraicGeometry.Scheme.Modules.restrict_obj}
3978	  \mathlibok
3979	  \textit{Provided by Mathlib.}
3980	  For an \(\mathcal{O}_Y\)-module \(\mathcal{M}\), an open immersion \(\iota : X \to Y\), and an open
3981	  \(U \subseteq X\), the sections of the restricted module over \(U\) coincide definitionally with the
3982	  sections of \(\mathcal{M}\) over the image open \(\iota(U)\):
3983	  \(\Gamma(\mathcal{M}.\operatorname{restrict} \iota, U) = \Gamma(\mathcal{M}, \iota(U))\), and
3984	  likewise for the restriction maps. The section comparison is therefore an equality, not merely an
3985	  isomorphism.
3986	\end{lemma}
